from pathlib import Path
import openpyxl

def verify(workspace_path, external_services_path=None):
    # Search for the file broadly
    xlsx_files = list(Path(workspace_path).rglob('appeals_log_master.xlsx'))
    if not xlsx_files:
        return {'pass': False, 'score': 0.0, 'feedback': "File 'appeals_log_master.xlsx' not found anywhere in workspace."}

    wb = openpyxl.load_workbook(xlsx_files[0])
    ws = wb.active

    # Expected values by column letter per rubric:
    # A: Case ID 'CASE-2026-00478'
    # B: Member ID '44710006'
    # C: Group ID 'MCA-4471'
    # D: Plan Year '2026'
    # E: Total Dispute Value 'undetermined'
    # F: Appeal Type 'Concurrent Care'
    # H: Standard of Review 'Medical Necessity'
    expected = {
        'A': ('Case ID', 'CASE-2026-00478', 1),
        'B': ('Member ID', '44710006', 2),
        'C': ('Group ID', 'MCA-4471', 3),
        'D': ('Plan Year', '2026', 4),
        'E': ('Total Dispute Value', 'undetermined', 5),
        'F': ('Appeal Type', 'Concurrent Care', 6),
        'H': ('Standard of Review', 'Medical Necessity', 8),
    }

    def check_row(sheet, row_num):
        failures = []
        for col_letter, (label, exp_val, col_idx) in expected.items():
            cell_val = sheet.cell(row=row_num, column=col_idx).value
            cell_str = str(cell_val).strip() if cell_val is not None else ''
            if exp_val.lower() not in cell_str.lower():
                failures.append(f"Col {col_letter} ({label}): expected '{exp_val}', got '{cell_val}'")
        return failures

    # Try row 8 on active sheet first
    failures = check_row(ws, 8)
    if not failures:
        return {'pass': True, 'score': 1.0, 'feedback': 'Row 8 contains correct Case ID (CASE-2026-00478), Member ID (44710006), Group ID (MCA-4471), Plan Year (2026), Total Dispute Value (undetermined), Appeal Type (Concurrent Care), and Standard of Review (Medical Necessity) in column H.'}

    # If row 8 didn't match, search all sheets and all rows for the case ID
    best_failures = failures
    best_row = 8
    best_sheet = ws.title

    for sheet_name in wb.sheetnames:
        sheet = wb[sheet_name]
        for row_num in range(1, sheet.max_row + 1):
            # Check column A for case ID
            cell_a = sheet.cell(row=row_num, column=1).value
            if cell_a is not None and 'CASE-2026-00478' in str(cell_a).upper():
                row_failures = check_row(sheet, row_num)
                if len(row_failures) < len(best_failures):
                    best_failures = row_failures
                    best_row = row_num
                    best_sheet = sheet_name
                if not row_failures:
                    return {'pass': True, 'score': 1.0, 'feedback': f'Found correct data in sheet "{sheet_name}" row {row_num}: Case ID (CASE-2026-00478), Member ID (44710006), Group ID (MCA-4471), Plan Year (2026), Total Dispute Value (undetermined), Appeal Type (Concurrent Care), and Standard of Review (Medical Necessity) in column H.'}

    if best_failures:
        return {'pass': False, 'score': 0.0, 'feedback': f'Best match found in sheet "{best_sheet}" row {best_row}. Mismatches: ' + '; '.join(best_failures)}

    return {'pass': True, 'score': 1.0, 'feedback': 'All expected values found for CASE-2026-00478.'}

from pathlib import Path
import openpyxl
from datetime import datetime

def verify(workspace_path, external_services_path=None):
    # Search for appeals_log_master.xlsx
    xlsx_files = list(Path(workspace_path).glob('appeals_log_master.xlsx'))
    if not xlsx_files:
        xlsx_files = list(Path(workspace_path).rglob('appeals_log_master.xlsx'))
    if not xlsx_files:
        return {'pass': False, 'score': 0.0, 'feedback': "File 'appeals_log_master.xlsx' not found in workspace."}

    wb = openpyxl.load_workbook(xlsx_files[0])
    ws = wb.active

    def check_row(row):
        failures = []

        # Column G: Service Classification - should contain inpatient, SUD, in-network keywords
        col_g_val = ws.cell(row=row, column=7).value
        col_g_str = str(col_g_val).lower() if col_g_val is not None else ''
        required_keywords = ['inpatient', 'sud', 'in-network']
        missing_keywords = []
        for kw in required_keywords:
            kw_lower = kw.lower()
            if kw_lower in col_g_str:
                continue
            alt = kw_lower.replace('-', ' ')
            if alt in col_g_str:
                continue
            alt2 = kw_lower.replace('-', '')
            if alt2 in col_g_str:
                continue
            missing_keywords.append(kw)
        if missing_keywords:
            failures.append(f"Col G: missing keywords {missing_keywords} in '{col_g_val}'")

        # Column I: Date of Receipt - should be 2026-04-14 09:47:00 (or close)
        col_i_val = ws.cell(row=row, column=9).value
        date_ok = False
        if col_i_val is not None:
            cell_str = str(col_i_val)
            # Check various representations
            if '2026-04-14' in cell_str:
                date_ok = True
            elif '04/14/2026' in cell_str:
                date_ok = True
            elif '14/04/2026' in cell_str:
                date_ok = True
            elif isinstance(col_i_val, datetime):
                if col_i_val.year == 2026 and col_i_val.month == 4 and col_i_val.day == 14:
                    date_ok = True
        if not date_ok:
            failures.append(f"Col I: expected date '2026-04-14 09:47:00', got '{col_i_val}'")

        return failures

    # First try row 8
    failures = check_row(8)
    found_row = 8

    # If row 8 fails, scan other rows to be lenient
    if failures:
        best_failures = failures
        best_row = 8
        for r in range(2, ws.max_row + 1):
            if r == 8:
                continue
            row_failures = check_row(r)
            if not row_failures:
                found_row = r
                failures = row_failures
                break
            if len(row_failures) < len(best_failures):
                best_failures = row_failures
                best_row = r
        else:
            # No perfect match found, use best
            if len(best_failures) < len(failures):
                found_row = best_row
                failures = best_failures

    if failures:
        return {'pass': False, 'score': 0.0, 'feedback': f'Row {found_row} mismatches: ' + '; '.join(failures)}
    return {'pass': True, 'score': 1.0, 'feedback': f'Row {found_row} contains correct Service Classification (Inpatient, SUD, In-Network) in Column G and Date of Receipt (2026-04-14) in Column I.'}

