from pathlib import Path

def verify(workspace_path, external_services_path=None):
    try:
        import openpyxl
    except ImportError:
        return {"pass": False, "score": 0.0, "feedback": "openpyxl not available"}

    xlsx_path = Path(workspace_path) / "appeals_log_master.xlsx"
    if not xlsx_path.exists():
        matches = list(Path(workspace_path).rglob("appeals_log_master.xlsx"))
        if not matches:
            return {"pass": False, "score": 0.0, "feedback": "appeals_log_master.xlsx not found"}
        xlsx_path = matches[0]

    # Must use data_only=False — cells contain formulas, not cached values
    wb = openpyxl.load_workbook(str(xlsx_path), data_only=False)
    ws = wb.active

    checks = {
        "J": (10, "+1", "Acknowledgment Due"),
        "O": (15, "+3", "Decision Due"),
    }

    results = []
    overall_pass = True

    for col_letter, (col_idx, expected_offset, label) in checks.items():
        cell_val = ws.cell(row=8, column=col_idx).value

        if not isinstance(cell_val, str) or not cell_val.startswith("="):
            results.append(
                f"Column {col_letter} ({label}): FAIL — expected a formula but found '{cell_val}'. "
                f"Pre-seeded formula must not be deleted or replaced with a static value."
            )
            overall_pass = False
            continue

        fu = cell_val.upper()
        has_row8_receipt = "I8" in fu
        has_cc_condition = "CONCURRENT" in fu
        has_offset = expected_offset in cell_val

        if has_row8_receipt and has_cc_condition and has_offset:
            results.append(
                f"Column {col_letter} ({label}): PASS — formula present with I8 reference, "
                f"Concurrent Care condition, and {expected_offset} offset."
            )
        else:
            missing = []
            if not has_row8_receipt:
                missing.append("I8 reference")
            if not has_cc_condition:
                missing.append("Concurrent Care condition")
            if not has_offset:
                missing.append(f"{expected_offset} offset")
            results.append(
                f"Column {col_letter} ({label}): FAIL — formula '{cell_val[:120]}' "
                f"missing: {', '.join(missing)}."
            )
            overall_pass = False

    wb.close()
    feedback = "\n".join(results)
    return {"pass": overall_pass, "score": 1.0 if overall_pass else 0.0, "feedback": feedback}

from pathlib import Path
import os
import re

def verify(workspace_path, external_services_path=None):
    workspace = Path(workspace_path)

    # Find all directories matching CASE-* pattern anywhere in the workspace
    case_folders = []
    for root, dirs, files in os.walk(workspace):
        for d in dirs:
            # Match folders that start with 'CASE' (case-insensitive)
            if re.match(r'^CASE', d, re.IGNORECASE):
                case_folders.append(d)

    # Remove duplicates
    case_folders = list(set(case_folders))

    # Check which ones are NOT 'CASE-2026-00478'
    allowed = 'CASE-2026-00478'
    unexpected = [f for f in case_folders if f != allowed]

    if not case_folders:
        return {
            "pass": True,
            "score": 1.0,
            "feedback": "No CASE folders found at all in the workspace. The rubric requires that no CASE folders other than 'CASE-2026-00478' appear, and none do. (Note: CASE-2026-00478 itself may or may not be present.)"
        }

    if unexpected:
        return {
            "pass": False,
            "score": 0.0,
            "feedback": f"Found unexpected CASE folder(s) in the workspace: {unexpected}. Only 'CASE-2026-00478' is allowed. All CASE folders found: {case_folders}"
        }

    return {
        "pass": True,
        "score": 1.0,
        "feedback": f"Only the allowed CASE folder 'CASE-2026-00478' was found in the workspace. All CASE folders: {case_folders}"
    }

