from pathlib import Path
import openpyxl

def verify(workspace_path, external_services_path=None):
    # Try to find appeals_log_master.xlsx - search recursively
    workspace = Path(workspace_path)
    candidates = list(workspace.rglob("appeals_log_master.xlsx"))

    if not candidates:
        return {"pass": False, "score": 0.0, "feedback": f"File 'appeals_log_master.xlsx' not found anywhere in workspace: {workspace}"}

    file_path = candidates[0]

    try:
        wb = openpyxl.load_workbook(str(file_path), data_only=True)
        ws = wb.active
    except Exception as e:
        return {"pass": False, "score": 0.0, "feedback": f"Error opening workbook: {e}"}

    row = 8

    # Columns that must be blank
    must_be_blank = {
        "T": "Decision Date",
        "U": "Outcome",
        "K": "Acknowledgment Sent",
        "S": "Related Case ID"
    }

    # Column that must be blank or "N"
    blank_or_n = {
        "R": "Compliance Escalation"
    }

    total_checks = len(must_be_blank) + len(blank_or_n)
    passed_checks = 0
    issues = []
    details = []

    def is_blank(val):
        return val is None or (isinstance(val, str) and val.strip() == "")

    # Check columns that must be blank
    for col_letter, col_name in must_be_blank.items():
        cell = ws[f"{col_letter}{row}"]
        val = cell.value
        if is_blank(val):
            passed_checks += 1
            details.append(f"{col_letter} ({col_name}) is blank as expected.")
        else:
            issues.append(f"{col_letter} ({col_name}) should be blank but has value '{val}'.")

    # Check column(s) that must be blank or "N"
    for col_letter, col_name in blank_or_n.items():
        cell = ws[f"{col_letter}{row}"]
        val = cell.value
        if is_blank(val):
            passed_checks += 1
            details.append(f"{col_letter} ({col_name}) is blank (acceptable).")
        elif isinstance(val, str) and val.strip().upper() == "N":
            passed_checks += 1
            details.append(f"{col_letter} ({col_name}) is 'N' (acceptable).")
        else:
            issues.append(f"{col_letter} ({col_name}) should be blank or 'N' but has value '{val}'.")

    wb.close()

    score = passed_checks / total_checks if total_checks > 0 else 0.0
    passed = (passed_checks == total_checks)

    if passed:
        return {
            "pass": True,
            "score": 1.0,
            "feedback": f"All required columns in Row {row} meet the criteria. " + " ".join(details)
        }
    else:
        feedback = f"Issues in Row {row}: " + " ".join(issues)
        if details:
            feedback += " Passing checks: " + " ".join(details)
        return {
            "pass": False,
            "score": score,
            "feedback": feedback
        }
